import React, { useEffect, useState, useCallback } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { BarChart, Bar, PieChart, Pie, Cell, Tooltip, ResponsiveContainer, XAxis, YAxis, CartesianGrid } from 'recharts';
import { Search, RefreshCw, Eye, Trash2, TrendingUp, AlertTriangle, CheckCircle, Clock } from 'lucide-react';
import toast from 'react-hot-toast';

const SEV_COLORS    = { low:'#22c55e', medium:'#eab308', high:'#f97316', critical:'#ef4444' };
const STATUS_COLORS = { pending:'#eab308', under_review:'#3b82f6', in_progress:'#f97316', resolved:'#22c55e', rejected:'#ef4444' };

export default function AuthorityDashboard() {
  const [stats,    setStats]    = useState(null);
  const [reports,  setReports]  = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [tab,      setTab]      = useState('overview');
  const [search,   setSearch]   = useState('');
  const [filters,  setFilters]  = useState({ status:'', severity:'' });
  const [updating, setUpdating] = useState(null);

  const loadData = useCallback(async () => {
    setLoading(true);
    try {
      const [s, r] = await Promise.all([
        axios.get('/api/reports/stats'),
        axios.get('/api/reports'),
      ]);
      setStats(s.data);
      setReports(r.data);
    } catch { toast.error('Failed to load data'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  const loadFiltered = useCallback(async () => {
    const params = { ...filters };
    if (search) params.search = search;
    const { data } = await axios.get('/api/reports', { params });
    setReports(data);
  }, [filters, search]);

  useEffect(() => { if (tab === 'reports') loadFiltered(); }, [filters, search, tab, loadFiltered]);

  const updateStatus = async (id, status) => {
    setUpdating(id);
    try {
      await axios.patch(`/api/reports/${id}/status`, { status });
      toast.success('Status updated');
      loadData();
    } catch { toast.error('Update failed'); }
    finally { setUpdating(null); }
  };

  const deleteReport = async (id) => {
    if (!window.confirm('Delete this report?')) return;
    try { await axios.delete(`/api/reports/${id}`); toast.success('Deleted'); loadData(); }
    catch { toast.error('Delete failed'); }
  };

  if (loading && !stats) return (
    <div style={{ display:'flex', alignItems:'center', justifyContent:'center', height:'60vh', color:'var(--text-muted)' }}>
      Loading…
    </div>
  );

  return (
    <div className="page-container">
      <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between', marginBottom:28, flexWrap:'wrap', gap:12 }}>
        <div>
          <h1 style={{ fontSize:24, marginBottom:4 }}>Authority Dashboard</h1>
          <p style={{ color:'var(--text-muted)', fontSize:14 }}>Manage and resolve road hazard reports</p>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={loadData}><RefreshCw size={14}/> Refresh</button>
      </div>

      {stats && (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(150px,1fr))', gap:14, marginBottom:28 }}>
          {[
            { label:'Total',      value:stats.total,       icon:<TrendingUp size={18}/>,   color:'var(--blue)',   bg:'var(--blue-dim)' },
            { label:'Pending',    value:stats.pending,     icon:<Clock size={18}/>,         color:'var(--yellow)', bg:'var(--yellow-dim)' },
            { label:'In Progress',value:stats.in_progress, icon:<RefreshCw size={18}/>,     color:'var(--accent)', bg:'var(--accent-glow)' },
            { label:'Resolved',   value:stats.resolved,    icon:<CheckCircle size={18}/>,   color:'var(--green)',  bg:'var(--green-dim)' },
            { label:'Critical',   value:stats.critical,    icon:<AlertTriangle size={18}/>, color:'var(--red)',    bg:'var(--red-dim)' },
          ].map(s => (
            <div key={s.label} style={{ background:'var(--bg-card)', border:'1px solid var(--border)', borderRadius:12, padding:'16px 18px' }}>
              <div style={{ display:'flex', justifyContent:'space-between', marginBottom:8 }}>
                <span style={{ fontSize:12, color:'var(--text-muted)', fontWeight:600, textTransform:'uppercase', letterSpacing:'0.04em' }}>{s.label}</span>
                <div style={{ background:s.bg, borderRadius:8, padding:6, color:s.color, display:'flex' }}>{s.icon}</div>
              </div>
              <div style={{ fontSize:30, fontWeight:800, color:s.color, fontFamily:'var(--font-display)', lineHeight:1 }}>{s.value}</div>
            </div>
          ))}
        </div>
      )}

      <div style={{ display:'flex', gap:2, background:'var(--bg-card)', border:'1px solid var(--border)', borderRadius:10, padding:4, width:'fit-content', marginBottom:24 }}>
        {['overview','reports'].map(t => (
          <button key={t} onClick={() => setTab(t)} style={{
            padding:'7px 18px', borderRadius:7, border:'none', fontSize:13, fontWeight:600,
            background: tab===t ? 'var(--accent)' : 'transparent',
            color: tab===t ? '#fff' : 'var(--text-muted)',
            cursor:'pointer', transition:'all 0.15s', textTransform:'capitalize'
          }}>{t === 'overview' ? '📊 Overview' : '📋 All Reports'}</button>
        ))}
      </div>

      {tab === 'overview' && stats && (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(300px,1fr))', gap:20 }}>
          <div className="card">
            <div style={{ fontSize:13, fontWeight:700, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:16 }}>By Severity</div>
            <ResponsiveContainer width="100%" height={200}>
              <BarChart data={stats.by_severity} margin={{ top:0, right:0, bottom:0, left:-20 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" vertical={false}/>
                <XAxis dataKey="severity" tick={{ fill:'var(--text-muted)', fontSize:12 }} axisLine={false} tickLine={false}/>
                <YAxis tick={{ fill:'var(--text-muted)', fontSize:12 }} axisLine={false} tickLine={false}/>
                <Tooltip contentStyle={{ background:'var(--bg-card)', border:'1px solid var(--border)', borderRadius:8, fontSize:13 }}/>
                <Bar dataKey="count" radius={[6,6,0,0]}>
                  {stats.by_severity.map((e,i) => <Cell key={i} fill={SEV_COLORS[e.severity] || '#888'}/>)}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>

          <div className="card">
            <div style={{ fontSize:13, fontWeight:700, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:16 }}>By Status</div>
            <ResponsiveContainer width="100%" height={200}>
              <PieChart>
                <Pie data={stats.by_status} dataKey="count" nameKey="status" cx="50%" cy="50%" outerRadius={75} innerRadius={35} paddingAngle={3}>
                  {stats.by_status.map((e,i) => <Cell key={i} fill={STATUS_COLORS[e.status] || '#888'}/>)}
                </Pie>
                <Tooltip contentStyle={{ background:'var(--bg-card)', border:'1px solid var(--border)', borderRadius:8, fontSize:13 }}
                  formatter={(v,n,p) => [v, p.payload.status.replace('_',' ')]}/>
              </PieChart>
            </ResponsiveContainer>
          </div>

          <div className="card">
            <div style={{ fontSize:13, fontWeight:700, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:16 }}>Hazard Types</div>
            {stats.by_hazard.slice(0,6).map((h,i) => {
              const pct = stats.total ? Math.round((h.count / stats.total) * 100) : 0;
              return (
                <div key={i} style={{ marginBottom:10 }}>
                  <div style={{ display:'flex', justifyContent:'space-between', fontSize:13, marginBottom:4 }}>
                    <span style={{ textTransform:'capitalize' }}>{h.hazard_type.replace('_',' ')}</span>
                    <span style={{ color:'var(--text-muted)' }}>{h.count} ({pct}%)</span>
                  </div>
                  <div style={{ height:6, background:'var(--border)', borderRadius:3 }}>
                    <div style={{ height:'100%', borderRadius:3, background:'var(--accent)', width: pct + '%' }}/>
                  </div>
                </div>
              );
            })}
          </div>

          <div className="card">
            <div style={{ fontSize:13, fontWeight:700, color:'var(--text-muted)', textTransform:'uppercase', letterSpacing:'0.05em', marginBottom:16 }}>Recent Reports</div>
            {stats.recent.map(r => (
              <Link key={r.id} to={`/reports/${r.id}`} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 10px', borderRadius:8, background:'var(--bg)', border:'1px solid var(--border)', marginBottom:8 }}>
                <div style={{ flex:1, minWidth:0 }}>
                  <div style={{ fontSize:13, fontWeight:600, overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{r.title}</div>
                  <div style={{ fontSize:11, color:'var(--text-muted)', marginTop:1 }}>{r.location_text}</div>
                </div>
                <span className={`badge badge-${r.severity}`}>{r.severity}</span>
              </Link>
            ))}
          </div>
        </div>
      )}

      {tab === 'reports' && (
        <div>
          <div style={{ display:'flex', gap:10, marginBottom:18, flexWrap:'wrap' }}>
            <div style={{ position:'relative', flex:1, minWidth:200 }}>
              <Search size={15} style={{ position:'absolute', left:12, top:'50%', transform:'translateY(-50%)', color:'var(--text-faint)' }}/>
              <input className="form-input" placeholder="Search…" style={{ paddingLeft:36 }}
                value={search} onChange={e => setSearch(e.target.value)}/>
            </div>
            <select className="form-input" style={{ width:160 }} value={filters.status} onChange={e => setFilters({...filters, status:e.target.value})}>
              <option value="">All Status</option>
              {['pending','under_review','in_progress','resolved','rejected'].map(s =>
                <option key={s} value={s}>{s.replace('_',' ')}</option>)}
            </select>
            <select className="form-input" style={{ width:150 }} value={filters.severity} onChange={e => setFilters({...filters, severity:e.target.value})}>
              <option value="">All Severity</option>
              {['low','medium','high','critical'].map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>

          <div style={{ overflowX:'auto', borderRadius:12, border:'1px solid var(--border)' }}>
            <table style={{ width:'100%', borderCollapse:'collapse', fontSize:13 }}>
              <thead>
                <tr style={{ background:'var(--bg-hover)', borderBottom:'1px solid var(--border)' }}>
                  {['Report','Location','Severity','Status','Date','Actions'].map(h => (
                    <th key={h} style={{ padding:'11px 14px', textAlign:'left', fontWeight:600, color:'var(--text-muted)', fontSize:12, textTransform:'uppercase', letterSpacing:'0.04em', whiteSpace:'nowrap' }}>{h}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {reports.length === 0 ? (
                  <tr><td colSpan={6} style={{ textAlign:'center', padding:40, color:'var(--text-muted)' }}>No reports found</td></tr>
                ) : reports.map((r, i) => (
                  <tr key={r.id} style={{ borderBottom:'1px solid var(--border)', background: i%2===0 ? 'var(--bg-card)' : 'var(--bg)' }}>
                    <td style={{ padding:'10px 14px', maxWidth:200 }}>
                      <Link to={`/reports/${r.id}`} style={{ color:'var(--text)', fontWeight:600 }}>
                        <div style={{ overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{r.title}</div>
                      </Link>
                      <div style={{ fontSize:11, color:'var(--text-faint)', marginTop:2 }}>{r.reporter_name}</div>
                    </td>
                    <td style={{ padding:'10px 14px', color:'var(--text-muted)', maxWidth:150 }}>
                      <div style={{ overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{r.location_text}</div>
                    </td>
                    <td style={{ padding:'10px 14px' }}><span className={`badge badge-${r.severity}`}>{r.severity}</span></td>
                    <td style={{ padding:'10px 14px' }}>
                      <select value={r.status} disabled={updating === r.id} onChange={e => updateStatus(r.id, e.target.value)}
                        style={{ background:'var(--bg)', border:'1px solid var(--border)', borderRadius:6, color:'var(--text)', padding:'4px 8px', fontSize:12, cursor:'pointer' }}>
                        {['pending','under_review','in_progress','resolved','rejected'].map(s =>
                          <option key={s} value={s}>{s.replace('_',' ')}</option>)}
                      </select>
                    </td>
                    <td style={{ padding:'10px 14px', color:'var(--text-muted)', whiteSpace:'nowrap' }}>{new Date(r.created_at).toLocaleDateString()}</td>
                    <td style={{ padding:'10px 14px' }}>
                      <div style={{ display:'flex', gap:6 }}>
                        <Link to={`/reports/${r.id}`} className="btn btn-ghost btn-sm" style={{ padding:'5px 10px' }}><Eye size={13}/></Link>
                        <button className="btn btn-danger btn-sm" style={{ padding:'5px 10px' }} onClick={() => deleteReport(r.id)}><Trash2 size={13}/></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
